"use client";
import { useState, useEffect, useRef } from "react";
import { usePathname, useRouter } from "next/navigation";

export default function Header({
                                   navLinks = [],
                                   user = { name: "Анна К.", initials: "АК", role: "Читатель", email: "anna.k@mail.ru" },
                                   notifCount = 3
                               }) {
    const [notifOpen, setNotifOpen] = useState(false);
    const [profileOpen, setProfileOpen] = useState(false);
    const headerRef = useRef(null);
    const router = useRouter();
    const pathname = usePathname();

    useEffect(() => {
        const handleClickOutside = (e) => {
            if (headerRef.current && !headerRef.current.contains(e.target)) {
                setNotifOpen(false);
                setProfileOpen(false);
            }
        };
        document.addEventListener("mousedown", handleClickOutside);
        return () => document.removeEventListener("mousedown", handleClickOutside);
    }, []);

    const handleNav = (href) => {
        router.push(href);
        setNotifOpen(false);
        setProfileOpen(false);
    };

    return (
        <header className="header" ref={headerRef}>
            <a href="/catalog" className="logo" onClick={(e) => { e.preventDefault(); handleNav("/catalog"); }}>
                <svg width="36" height="36" viewBox="0 0 40 40" fill="none" style={{ flexShrink: 0 }}>
                    <rect x="4" y="8" width="14" height="24" rx="2" fill="#ec9428" opacity="0.9" />
                    <rect x="10" y="6" width="14" height="24" rx="2" fill="#f6ca7d" opacity="0.9" />
                    <rect x="16" y="10" width="14" height="24" rx="2" fill="#4f7e4f" opacity="0.9" />
                </svg>
                Библиотека<span>Будущего</span>
            </a>

            <nav className="nav">
                {navLinks.map(link => (
                    <button
                        key={link.href}
                        className={`nav-link ${pathname === link.href ? "active" : ""}`}
                        onClick={() => handleNav(link.href)}
                    >
                        {link.label}
                    </button>
                ))}
            </nav>

            <div className="header-right">
                <div className="dropdown">
                    <button className="icon-btn" onClick={() => { setNotifOpen(!notifOpen); setProfileOpen(false); }}>
                        🔔 <span className="badge">{notifCount}</span>
                    </button>
                    {notifOpen && (
                        <div className="dropdown-menu">
                            <div className="dropdown-header">🔔 Уведомления</div>
                            <button className="dropdown-item" style={{ borderBottom: "1px solid rgba(255,255,255,0.06)" }}>Прочитать все</button>
                            <button className="dropdown-item" onClick={() => setNotifOpen(false)} style={{ position: "absolute", top: 8, right: 8, padding: 4 }}>✕</button>
                        </div>
                    )}
                </div>

                <div className={`dropdown ${profileOpen ? "open" : ""}`}>
                    <button className="user-btn" onClick={() => { setProfileOpen(!profileOpen); setNotifOpen(false); }}>
                        <div className="avatar" style={{ background: "linear-gradient(135deg, var(--sage-500), var(--sage-400))" }}>{user.initials}</div>
                        <div style={{ textAlign: "left" }}>
                            <div className="user-name">{user.name}</div>
                            <div style={{ fontSize: 11, color: "var(--ink-400)", marginTop: -2 }}>{user.role}</div>
                        </div>
                    </button>
                    <div className="dropdown-menu">
                        <div className="dropdown-header">
                            <div className="dropdown-header-name">{user.name}</div>
                            <div className="dropdown-header-email">{user.email}</div>
                        </div>
                        <button className="dropdown-item" onClick={() => handleNav("/dashboard")}>👤 Личный кабинет</button>
                        <div className="dropdown-divider" />
                        <button className="dropdown-item danger" onClick={() => handleNav("/login")}>🚪 Выйти</button>
                    </div>
                </div>
            </div>
        </header>
    );
}